// Evidence: httpsts-worked-http-server-ts-node-http-protocol-timeouts-4
// Competency: httpsts-worked-http-server-ts-node-http-protocol-timeouts-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_node_http_protocol_timeouts_4(protocol: "http/1.1" | "h2" | "h3", headersMs: number, requestMs: number, draining: boolean): { serve: boolean; reason: string } {
  if (protocol === "h3") return { serve: false, reason: "external-http3-boundary" };
  if (headersMs <= 0 || requestMs < headersMs) {
    return { serve: false, reason: "invalid-timeout-budget" };
  }
  if (draining) return { serve: false, reason: "draining" };
  return { serve: true, reason: protocol };
}

